import lxml.etree as ET
from io import StringIO

def process_soap_request(xml_string):
    # Parse the SOAP request with DTD validation
    parser = ET.XMLParser(dtd_validation=True, no_network=False)
    try:
        root = ET.parse(StringIO(xml_string), parser).getroot()
        
        # Extract the message body from the SOAP envelope
        body_element = root.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')
        if body_element is not None:
            return ET.tostring(body_element, encoding='unicode', method='xml').strip()
        else:
            raise ValueError("SOAP Body element not found")
    except ET.XMLSyntaxError as e:
        # Handle XML parsing errors
        print(f"XML parsing error: {e}")
        return None

